import xml.etree.ElementTree as ET
from typing import Dict

def parse_xml_config(filepath: str) -> Dict[str, str]:
    tree = ET.parse(filepath)
    root = tree.getroot()
    
    settings = {}
    
    for child in root:
        if child.tag == "setting":
            name = child.attrib["name"]
            value = child.text
            settings[name] = value
            
    return settings